import regex as re

# define normalize:
def strip_diacritics(s):
    # ASCII wise remove Arabic diacritics
    # We'll remove all characters with Unicode category Mn and tatweel U+0640
    return ''.join(ch for ch in unicodedata.normalize('NFKD', s) if unicodedata.category(ch) != 'Mn' and ch != '\u0640')

def normalize_ar(s):
    s = s.strip()
    s = strip_diacritics(s)
    # unify hamza forms to alef: ا, أ, إ, آ -> ا
    # replace alif maqsoora ى to ي? unify?
    # unify taa marbuta? Might not needed.
    # unify yaa w dotless? Not necessary.
    rep = {
        'أ':'ا','إ':'ا','آ':'ا','ٱ':'ا','ى':'ي','ة':'ه','ؤ':'و','ئ':'ي','ء':'ء', # maybe unify hamza seat
    }
    s2 = ''.join(rep.get(ch, ch) for ch in s)
    # remove punctuation except spaces
    # Keep Arabic letters and digits and spaces
    s2 = re.sub(r'[^\p{Arabic}\d\s]+', ' ', s2)
    # collapse spaces to single
    s2 = re.sub(r'\s+', ' ', s2)
    return s2.strip().lower()

def lcs_length(a, b):
    # dynamic programming minimal due to short strings; 
    # We'll compute LCS of two sequences (characters).
    n, m = len(a), len(b)
    dp = [0]*(m+1)
    for i in range(1, n+1):
        prev = 0
        for j in range(1, m+1):
            tmp = dp[j]
            if a[i-1] == b[j-1]:
                dp[j] = prev + 1
            else:
                dp[j] = max(dp[j], dp[j-1])
            prev = tmp
    return dp[m]

def robust_similarity(span, cand):
    na = normalize_ar(span)
    nb = normalize_ar(cand)
    if not na or not nb:
        return 0.0
    lcs = lcs_length(na, nb)
    # measure coverage of the span by the candidate
    return lcs / max(1, len(na))

